+/** Run a delegated agent without exposing its intermediate stream to the parent chat. */
+async function runDelegatedAgent(
+  agentId: string,
+  instructions: string,
+  request: ChatRequest,
+  abortController: AbortController,
+  debugMode: boolean,
+  delegationPath: ReadonlySet<string>
+): Promise<{ content: string; error?: string }> {
+  if (delegationPath.has(agentId)) {
+    return { content: "Circular agent delegation detected.", error: "Circular agent delegation detected." };
+  }
+
+  const provider = globalRegistry.getProviderForAgent(agentId);
+  const agentConfig = globalRegistry.getAgent(agentId);
+  if (!provider || !agentConfig) {
+    return { content: `Agent '${agentId}' not found or provider not available`, error: `Agent '${agentId}' not found or provider not available` };
+  }
+
+  const nextPath = new Set(delegationPath).add(agentId);
+  const context: NonNullable<ProviderChatRequest["context"]> = [];
+  const text: string[] = [];
+
+  // A delegated tool ends the current provider turn. Re-invoke it after feeding
+  // the single tool_result back as user context, just like a normal tool loop.
+  while (true) {
+    let delegation: { toolUseId: string; input: DelegationInput } | undefined;
+    try {
+      for await (const response of provider.executeChat({
+        ...getProviderRequest(request, agentConfig, context),
+        message: instructions,
+      }, getProviderOptions(agentConfig, abortController, debugMode))) {
+        if (response.type === "text" && response.content) text.push(response.content);
+        if (response.type === "error") return { content: response.error || "Delegated agent failed.", error: response.error || "Delegated agent failed." };
+        if (response.type === "tool_use" && response.toolName === "delegate_task") {
+          delegation = { toolUseId: response.toolUseId || `delegate-${crypto.randomUUID()}`, input: parseDelegationInput(response.toolInput) };
+          break;
+        }
+      }
+    } catch (error) {
+      const message = error instanceof Error ? error.message : String(error);
+      return { content: message, error: message };
+    }
+
+    if (!delegation) return { content: text.join("") || NO_DELEGATION_OUTPUT };
+    const target = typeof delegation.input.agent_id === "string" ? delegation.input.agent_id : "";
+    const childInstructions = typeof delegation.input.instructions === "string" ? delegation.input.instructions : "";
+    const child = await runDelegatedAgent(target, childInstructions, request, abortController, debugMode, nextPath);
+    const result: ToolResult = { type: "tool_result", is_error: !!child.error, content: child.content || NO_DELEGATION_OUTPUT, tool_use_id: delegation.toolUseId };
+    context.push({ role: "user", content: JSON.stringify(result) });
+  }
+}
